const LeafLogo = ({ darkBg = false }) => (
  <svg
    width="160"
    height="38"
    viewBox="0 0 160 38"
    xmlns="http://www.w3.org/2000/svg"
    aria-label="Satvik Havan"
  >
    {/* Leaf mark */}
    <path
      d="M19 30 C19 30 5 21 7 10 C9 4 19 2 19 2 C19 2 29 4 31 10 C33 21 19 30 19 30Z"
      fill={darkBg ? "#E8970A" : "#C8520A"}
    />
    {/* Center vein */}
    <line x1="19" y1="5" x2="19" y2="28"
      stroke={darkBg ? "#2C1408" : "#FDF6E3"}
      strokeWidth="1"
      strokeDasharray="2,2"
    />
    {/* Upper veins */}
    <line x1="19" y1="13" x2="12" y2="18"
      stroke={darkBg ? "#2C1408" : "#FDF6E3"}
      strokeWidth="0.8" opacity="0.75"
    />
    <line x1="19" y1="13" x2="26" y2="18"
      stroke={darkBg ? "#2C1408" : "#FDF6E3"}
      strokeWidth="0.8" opacity="0.75"
    />
    {/* Lower veins */}
    <line x1="19" y1="20" x2="13" y2="24"
      stroke={darkBg ? "#2C1408" : "#FDF6E3"}
      strokeWidth="0.8" opacity="0.5"
    />
    <line x1="19" y1="20" x2="25" y2="24"
      stroke={darkBg ? "#2C1408" : "#FDF6E3"}
      strokeWidth="0.8" opacity="0.5"
    />
    {/* Brand name */}
    <text
      x="42"
      y="15"
      fontFamily="'Yeseva One', serif"
      fontSize="14"
      fill={darkBg ? "#FDF6E3" : "#2C1408"}
    >
      Satvik
    </text>
    <text
      x="42"
      y="30"
      fontFamily="'Yeseva One', serif"
      fontSize="14"
      fill={darkBg ? "#F5C842" : "#C8520A"}
    >
      Havan
    </text>
  </svg>
);

const NAV_LINKS = [
  { to: "/", label: "Home" },
  { to: "/herbs", label: "Buy Herbs" },
  { to: "/booking", label: "Book Pandit Ji" },
  { to: "/about", label: "About" },
  { to: "/contact", label: "Contact" },
];

export default function Navbar() {
  const [open, setOpen] = useState(false);
  const { pathname } = useLocation();

  return (
    <>
      <nav className="navbar">
        <div className="navbar-container">
          <Link
            to="/"
            style={{ textDecoration: "none", lineHeight: 1 }}
            onClick={() => setOpen(false)}
            aria-label="Satvik Havan Home"
          >
            <LeafLogo darkBg={false} />
          </Link>

          <ul className={`nav-links${open ? " open" : ""}`}>
            {NAV_LINKS.map((l) => (
              <li key={l.to}>
                <Link
                  to={l.to}
                  onClick={() => setOpen(false)}
                  style={{
                    color: pathname === l.to ? "var(--saffron)" : undefined,
                    fontWeight: pathname === l.to ? 600 : undefined,
                  }}
                >
                  {l.label}
                </Link>
              </li>
            ))}
            <li>
              <a
                href={waLink("Namaste! I want to order herbs / book a pandit.")}
                target="_blank"
                rel="noreferrer"
                className="nav-wa-btn"
                onClick={() => setOpen(false)}
              >
                <WaIcon /> WhatsApp
              </a>
            </li>
          </ul>

          <button
            className={`hamburger${open ? " open" : ""}`}
            onClick={() => setOpen(!open)}
            aria-label="Toggle menu"
          >
            <span />
            <span />
            <span />
          </button>
        </div>
      </nav>

      {/* Floating WhatsApp Button */}
      <a
        href={waLink("Namaste! I want to order herbs / book a pandit.")}
        target="_blank"
        rel="noreferrer"
        className="float-wa"
        title="Chat on WhatsApp"
      >
        <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
          <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/>
        </svg>
      </a>
    </>
  );
}
